module binary_counter(clk, rst, count);

   input clk, rst;
   output reg [3:0] count;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
   begin
      if (rst) // reset counter to 0
         count <= 4'b0000;
      else // increment counter
         count <= count + 1;
   end

endmodule
